SET academy_metadata = '{"displayName":"UK – Visitor Visa (Standard Visitor)","shortDescription":"UKVI Standard Visitor · Tourism, family, business · 6-month stay","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 6 Jun 2026","learningLevel":"Beginner","learningMinutes":15,"policyAlert":{"active":true,"date":"6 Jun 2026","summary":"Confirm current Standard Visitor visa fee (£115 for 6 months) on gov.uk before quoting clients."},"alert":{"title":"Genuine visitor intent","body":"Officers assess whether applicant will leave UK after visit. Weak ties to India and vague purpose are top refusal reasons."},"tags":[{"label":"Active service","variant":"success"},{"label":"Ties evidence critical","variant":"warning"},{"label":"3–6 weeks","variant":"neutral"},{"label":"Online – UKVI","variant":"neutral"}],"chips":[{"label":"3–6 weeks processing","variant":"neutral"},{"label":"£115 (6 months)","variant":"neutral"},{"label":"Strong ties required","variant":"warning"},{"label":"VAC biometrics","variant":"success"}],"kpis":[{"label":"Processing time","value":"3–6w","sub":"Standard visitor outside UK","tone":"primary"},{"label":"Government fee","value":"£115","sub":"6-month visit (2026)","tone":"warning"},{"label":"Our approval rate","value":"74%","sub":"~62% industry benchmark","tone":"success"},{"label":"Required docs","value":"9","sub":"+ invitation if applicable","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt only","tone":"primary"}],"about":[{"label":"Description","value":"Standard Visitor visa for tourism, visiting family/friends, or short business activities in the UK. Most Indian applicants apply online and attend VAC biometrics."},{"label":"Eligible applicants","value":"Temporary visit purpose · Funds for trip · Strong ties to India · Genuine intention to leave UK · Clean immigration history"},{"label":"No work or long-term study","value":"Visitors cannot work or access public funds. Short courses up to 6 months may be permitted—verify rules.","warning":true},{"label":"Key authority","value":"UK Visas and Immigration (UKVI) — Home Office"},{"label":"After approval","value":"Visa vignette in passport; entry decision at border. Respect visit duration—overstay affects future applications."}],"eligibility":[{"criterion":"Valid passport","met":true},{"criterion":"Clear visit purpose","met":true,"note":"Tourism, family, or permitted business activity"},{"criterion":"Proof of funds","met":true,"note":"Cover trip cost or credible sponsor"},{"criterion":"Strong ties to India","met":true,"note":"Employment, business, property, family"},{"criterion":"Accommodation and travel plans","met":true,"note":"Itinerary or host invitation"},{"criterion":"Biometrics completed","met":false},{"criterion":"No prior immigration breaches undisclosed","met":true}],"redFlagsBanner":"After refusal, review refusal letter grounds. Do not reapply with same weak ties evidence without material improvement.","redFlags":[{"title":"Weak ties to India","description":"Unemployed, no assets, vague return plan.","fix":"Employment letter, business proof, property, family obligations","severity":"Very common"},{"title":"Insufficient funds","description":"Cannot explain trip funding or recent large deposits.","fix":"Bank history, ITR, sponsor letter with host support if applicable","severity":"Very common"},{"title":"Purpose mismatch","description":"Tourism application with unclear activity or long stay without reason.","fix":"Realistic itinerary; explain duration; host invitation for family visits","severity":"Common"},{"title":"Prior refusals not addressed","description":"UK or Schengen refusals hidden.","fix":"Disclose and explain changed circumstances","severity":"High"},{"title":"Immigration history concerns","description":"Prior overstays or refusals from UK/allies.","fix":"Honest disclosure; legal advice if complex","severity":"High"},{"title":"Cover letter too generic","description":"Template letter not matching client profile.","fix":"Personalised letter with specific dates, purpose, and ties","severity":"Medium"}],"faqs":[{"q":"Can we guarantee visitor visa approval?","a":"No. UKVI decides each case on merits. We strengthen documentation but never promise approval."},{"q":"How much funds to show?","a":"Enough to cover flights, accommodation, and daily expenses. No fixed amount—must be credible for trip duration."},{"q":"Is invitation letter required?","a":"Recommended for family visits. Host should provide invitation, status proof, and accommodation details."},{"q":"Can visitor switch to student visa in UK?","a":"Generally cannot switch from visitor to student inside UK—apply from outside. Verify current rules."},{"q":"How long can visitor stay?","a":"Usually up to 6 months per visit on standard visitor visa. Officer may grant shorter period."},{"q":"Does prior Schengen refusal affect UK visa?","a":"Must disclose all refusals. UKVI considers overall immigration history."},{"q":"Can visitor work?","a":"No paid or unpaid work except limited permitted business visitor activities."},{"q":"Priority service available?","a":"Check gov.uk for current priority/super priority options and VAC availability in India."},{"q":"What is Description for this service?","a":"Standard Visitor visa for tourism, visiting family/friends, or short business activities in the UK. Most Indian applicants apply online and attend VAC biometrics."},{"q":"What is Eligible applicants for this service?","a":"Temporary visit purpose · Funds for trip · Strong ties to India · Genuine intention to leave UK · Clean immigration history"},{"q":"What is No work or long-term study for this service?","a":"Visitors cannot work or access public funds. Short courses up to 6 months may be permitted—verify rules."},{"q":"Important note on No work or long-term study?","a":"Visitors cannot work or access public funds. Short courses up to 6 months may be permitted—verify rules."},{"q":"What is Key authority for this service?","a":"UK Visas and Immigration (UKVI) — Home Office"},{"q":"What is After approval for this service?","a":"Visa vignette in passport; entry decision at border. Respect visit duration—overstay affects future applications."},{"q":"Is Valid passport required?","a":"Valid passport is typically required."},{"q":"Is Clear visit purpose required?","a":"Tourism, family, or permitted business activity"},{"q":"Is Proof of funds required?","a":"Cover trip cost or credible sponsor"},{"q":"Is Strong ties to India required?","a":"Employment, business, property, family"},{"q":"Is Accommodation and travel plans required?","a":"Itinerary or host invitation"},{"q":"Is Biometrics completed required?","a":"Assess whether Biometrics completed is satisfied for this case."},{"q":"Is No prior immigration breaches undisclosed required?","a":"No prior immigration breaches undisclosed is typically required."},{"q":"What is the Processing time?","a":"3–6w — Standard visitor outside UK"},{"q":"What is the Government fee?","a":"£115 — 6-month visit (2026)"},{"q":"What is the Our approval rate?","a":"74% — ~62% industry benchmark"},{"q":"What is the Required docs?","a":"9 — + invitation if applicable"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt only"},{"q":"What if the client has Weak ties to India?","a":"Employment letter, business proof, property, family obligations"},{"q":"Why is Weak ties to India a problem?","a":"Unemployed, no assets, vague return plan."},{"q":"What if the client has Insufficient funds?","a":"Bank history, ITR, sponsor letter with host support if applicable"},{"q":"Why is Insufficient funds a problem?","a":"Cannot explain trip funding or recent large deposits."}],"compliance":["Client service agreement and consent on file before application","Never guarantee visa approval","Separate consultancy and UKVI fees in quotes","Do not advise working in UK on visitor visa"],"proTips":["Personalise cover letter—avoid copy-paste templates","For family visits, collect host''s BR status proof and invitation","Show employment leave letter even for tourism","Keep trip duration realistic for stated purpose","Save refusal letters for future reapplication strategy"],"postApproval":["Explain visit duration and no-work rule","Remind client to carry supporting documents to border","Advise on travel insurance","Note reapplication rules if visit purpose changes later"],"performance":{"ourRate":74,"industryRate":62,"stats":[{"label":"Files this year","value":"88"},{"label":"Approved","value":"65"},{"label":"Refused","value":"19"},{"label":"Withdrawn","value":"4"}]},"approvalFactors":[{"label":"Our rate vs industry","ours":74,"benchmark":62},{"label":"Ties documentation","ours":71,"benchmark":55},{"label":"Cover letter quality","ours":76,"benchmark":58},{"label":"First-submit completeness","ours":85,"benchmark":68}],"timeline":[{"weeks":"1","title":"Counseling, purpose assessment, fee agreement"},{"weeks":"1–2","title":"Document collection and cover letter"},{"weeks":"2–3","title":"UKVI submission and biometrics"},{"weeks":"3–6","title":"UKVI processing"}],"relatedServices":[{"label":"UK – Student Visa","libraryId":""},{"label":"UK – Spouse Visa","libraryId":""},{"label":"UK – Skilled Worker","libraryId":""}],"changelog":[{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded FAQs to 30 counselor Q&A pairs."},{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded quiz to 75 levelled questions (25 per level)."},{"version":"v1.0","date":"6 Jun 2026","author":"Service Library","summary":"Initial UK Standard Visitor counselor content."}],"staffNotes":[{"author":"Documentation team","date":"6 Jun 2026","text":"Parents visiting children in UK need strong India ties—property and spouse in India critical."}],"resources":[{"title":"GOV.UK — Standard Visitor visa","url":"https://www.gov.uk/standard-visitor","description":"Official visitor visa requirements"},{"title":"GOV.UK — Visit the UK","url":"https://www.gov.uk/visit-uk","description":"Overview of visiting UK"},{"title":"GOV.UK — Visa fees","url":"https://www.gov.uk/visa-fees","description":"Current UK visa fee list"},{"title":"GOV.UK — Visa processing times","url":"https://www.gov.uk/visa-processing-times","description":"Current processing estimates"},{"title":"GOV.UK — Supporting documents guidance","url":"https://www.gov.uk/guidance/visitor-visa-guide-to-supporting-documents","description":"Document guidance for visitors"}],"quiz":[{"question":"Standard Visitor visa (6 months) fee approx (2026)?","options":["£524","£115","£1,846","£50"],"correctIndex":1,"explanation":"Verify on gov.uk visa fees page.","level":1},{"question":"Top refusal reason for Indian visitors?","options":["Passport colour","Weak ties / not genuine visitor","Wrong photo size only","Hotel brand"],"correctIndex":1,"explanation":"Officers must be satisfied applicant will leave UK.","level":1},{"question":"Can Standard Visitors work in UK?","options":["Yes, full-time","No","Yes, if invited","Only remote"],"correctIndex":1,"explanation":"Work not permitted on visitor route.","level":1},{"question":"Family visit applications benefit from:","options":["No documents","Host invitation and ties evidence","Guaranteed approval letter","Employment in UK"],"correctIndex":1,"explanation":"Invitation and host status strengthen purpose.","level":1},{"question":"After refusal, best practice:","options":["Reapply same day unchanged","Address refusal grounds before reapplying","Hide prior refusal","Guarantee next approval"],"correctIndex":1,"explanation":"Material improvement needed for reapplication.","level":1},{"level":1,"question":"For UK – Visitor Visa (Standard Visitor), which statement about Description is correct?","options":["Standard Visitor visa for tourism, visiting family/friends, or short business activities in the UK. Most Indian applicants apply online and attend VAC biometri…","Temporary visit purpose · Funds for